            assert_eq!(*variant, deserialized);
        }
    }

    #[test]
    fn value_space_serde_uses_snake_case() {
        assert_eq!(
            serde_json::to_string(&MockValueSpace::LiveFirst).expect("serialize"),
            "\"live_first\""
        );
        assert_eq!(
            serde_json::to_string(&MockValueSpace::FixedSet).expect("serialize"),
            "\"fixed_set\""
        );
    }

    // -- Connection failure classification --

    #[test]
    fn classify_econnrefused() {
        let result = classify_connection_failure("Error: connect ECONNREFUSED 127.0.0.1:5432");
        assert_eq!(result, Some(ConnectionFailureKind::ConnectionRefused));
    }

    #[test]
    fn classify_connection_refused_lowercase() {
        let result = classify_connection_failure("connection refused");
        assert_eq!(result, Some(ConnectionFailureKind::ConnectionRefused));
    }

    #[test]
    fn classify_dns_enotfound() {
        let result = classify_connection_failure("Error: getaddrinfo ENOTFOUND api.example.com");
        assert_eq!(result, Some(ConnectionFailureKind::DnsFailure));
    }

    #[test]
    fn classify_dns_no_such_host() {
        let result = classify_connection_failure("dial tcp: lookup api.example.com: no such host");
        assert_eq!(result, Some(ConnectionFailureKind::DnsFailure));
    }

    #[test]
    fn classify_getaddrinfo() {
        let result = classify_connection_failure("getaddrinfo failed");
        assert_eq!(result, Some(ConnectionFailureKind::DnsFailure));
    }

    #[test]
    fn classify_auth_401() {
        let result = classify_connection_failure("HTTP 401 Unauthorized");
        assert_eq!(result, Some(ConnectionFailureKind::AuthError));
    }

    #[test]
    fn classify_auth_forbidden() {
        let result = classify_connection_failure("403 Forbidden");
        assert_eq!(result, Some(ConnectionFailureKind::AuthError));
    }

    #[test]
    fn classify_auth_access_denied() {
        let result = classify_connection_failure("access denied for user 'root'");
        assert_eq!(result, Some(ConnectionFailureKind::AuthError));
    }

