//! dependency, classify the outcome, and fall back to autonomous mocking
//! only when the dependency is unavailable.

use serde::{Deserialize, Serialize};

// ---------------------------------------------------------------------------
// Connection failure heuristic patterns
// ---------------------------------------------------------------------------

/// Substrings in error messages that indicate a connection was refused.
pub const CONN_REFUSED_PATTERNS: &[&str] =
    &["ECONNREFUSED", "connection refused", "Connection refused"];

/// Substrings that indicate DNS resolution failure.
pub const DNS_FAILURE_PATTERNS: &[&str] = &[
    "ENOTFOUND",
    "EAI_AGAIN",
    "dns resolution failed",
    "getaddrinfo",
    "no such host",
