pub const TIMEOUT_PATTERNS: &[&str] = &[
    "ETIMEDOUT",
    "ESOCKETTIMEDOUT",
    "ENETUNREACH",
    "timeout",
    "timed out",
    "request timeout",
];

// ---------------------------------------------------------------------------
// MockValueSpace enum
// ---------------------------------------------------------------------------

/// Strategy for sourcing mock return values during exploration.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum MockValueSpace {
    /// Call the real dependency first. On success, record the result for the
    /// behavior map. On connection failure, switch to [`Autonomous`](MockValueSpace::Autonomous).
    LiveFirst,

    /// Use a fixed set of pre-configured return values (from user config or
    /// behavior-map replay). No live calls are made.
    FixedSet,

    /// Generate return values autonomously based on type information and
    /// heuristics. Used as a fallback when the real dependency is unavailable.
    Autonomous,

    /// Use a user-provided seed value as the initial mock, then mutate it
    /// for subsequent calls using input-generation strategies.
    Seeded,
