pub fn classify_connection_failure(error_message: &str) -> Option<ConnectionFailureKind> {
    if CONN_REFUSED_PATTERNS
        .iter()
        .any(|p| error_message.contains(p))
    {
        return Some(ConnectionFailureKind::ConnectionRefused);
    }

    if DNS_FAILURE_PATTERNS
        .iter()
        .any(|p| error_message.contains(p))
    {
        return Some(ConnectionFailureKind::DnsFailure);
    }

    // Check timeout before auth because "timeout" is unambiguous, while
    // "401"/"403" could theoretically appear in non-auth contexts — but
    // timeout patterns never overlap with auth patterns.
    if TIMEOUT_PATTERNS.iter().any(|p| error_message.contains(p)) {
        return Some(ConnectionFailureKind::Timeout);
