            MockValueSpace::Seeded,
        ];
        for variant in &variants {
            let json = serde_json::to_string(variant).expect("serialize");
            let deserialized: MockValueSpace =
                serde_json::from_str(&json).expect("deserialize");
            assert_eq!(*variant, deserialized);
        }
    }

    #[test]
    fn value_space_serde_uses_snake_case() {
        assert_eq!(
            serde_json::to_string(&MockValueSpace::LiveFirst).expect("serialize"),
            "\"live_first\""
        );
        assert_eq!(
            serde_json::to_string(&MockValueSpace::FixedSet).expect("serialize"),
            "\"fixed_set\""
        );
    }

    // -- Connection failure classification --

    #[test]
    fn classify_econnrefused() {
        let result = classify_connection_failure("Error: connect ECONNREFUSED 127.0.0.1:5432");
        assert_eq!(result, Some(ConnectionFailureKind::ConnectionRefused));
    }

    #[test]
    fn classify_connection_refused_lowercase() {
        let result = classify_connection_failure("connection refused");
        assert_eq!(result, Some(ConnectionFailureKind::ConnectionRefused));
    }

    #[test]
    fn classify_dns_enotfound() {
        let result = classify_connection_failure("Error: getaddrinfo ENOTFOUND api.example.com");
        assert_eq!(result, Some(ConnectionFailureKind::DnsFailure));
    }

    #[test]
    fn classify_dns_no_such_host() {
        let result = classify_connection_failure("dial tcp: lookup api.example.com: no such host");
        assert_eq!(result, Some(ConnectionFailureKind::DnsFailure));
    }

    #[test]
    fn classify_getaddrinfo() {
        let result = classify_connection_failure("getaddrinfo failed");
        assert_eq!(result, Some(ConnectionFailureKind::DnsFailure));
    }

    #[test]
    fn classify_auth_401() {
        let result = classify_connection_failure("HTTP 401 Unauthorized");
        assert_eq!(result, Some(ConnectionFailureKind::AuthError));
    }

    #[test]
    fn classify_auth_forbidden() {
        let result = classify_connection_failure("403 Forbidden");
        assert_eq!(result, Some(ConnectionFailureKind::AuthError));
    }

    #[test]
    fn classify_auth_access_denied() {
        let result = classify_connection_failure("access denied for user 'root'");
        assert_eq!(result, Some(ConnectionFailureKind::AuthError));
    }

    #[test]
    fn classify_timeout_etimedout() {
        let result = classify_connection_failure("Error: connect ETIMEDOUT 10.0.0.1:443");
        assert_eq!(result, Some(ConnectionFailureKind::Timeout));
    }

    #[test]
    fn classify_timeout_timed_out() {
        let result = classify_connection_failure("request timed out after 30s");
        assert_eq!(result, Some(ConnectionFailureKind::Timeout));
    }

    #[test]
    fn classify_timeout_enetunreach() {
        let result = classify_connection_failure("ENETUNREACH");
        assert_eq!(result, Some(ConnectionFailureKind::Timeout));
    }

    #[test]
    fn classify_app_error_not_connection_failure() {
        assert_eq!(classify_connection_failure("ValidationError: name is required"), None);
        assert_eq!(classify_connection_failure("RangeError: index out of bounds"), None);
        assert_eq!(classify_connection_failure("TypeError: cannot read property of null"), None);
    }

    #[test]
    fn classify_empty_string_not_connection_failure() {
        assert_eq!(classify_connection_failure(""), None);
    }

    // -- classify_live_call --

    #[test]
    fn live_call_success_when_no_error() {
        assert_eq!(classify_live_call(None), LiveCallOutcome::Success);
    }

    #[test]
    fn live_call_connection_failure_on_econnrefused() {
        assert_eq!(
            classify_live_call(Some("ECONNREFUSED")),
            LiveCallOutcome::ConnectionFailure {
                failure_kind: ConnectionFailureKind::ConnectionRefused,
            }
        );
    }

    #[test]
    fn live_call_app_error_on_validation_error() {
        assert_eq!(
            classify_live_call(Some("ValidationError: bad input")),
            LiveCallOutcome::AppError
        );
    }

    // -- LiveFirstState transitions --

    #[test]
    fn untried_to_available_on_success() {
        let state = LiveFirstState::Untried;
        let next = state.transition(&LiveCallOutcome::Success);
        assert_eq!(next, LiveFirstState::Available);
    }

    #[test]
    fn untried_to_unavailable_on_connection_failure() {
        let state = LiveFirstState::Untried;
        let next = state.transition(&LiveCallOutcome::ConnectionFailure {
            failure_kind: ConnectionFailureKind::DnsFailure,
        });
        assert_eq!(
            next,
            LiveFirstState::Unavailable {
                reason: ConnectionFailureKind::DnsFailure,
            }
        );
    }

    #[test]
    fn untried_to_available_on_app_error() {
        let state = LiveFirstState::Untried;
        let next = state.transition(&LiveCallOutcome::AppError);
        assert_eq!(next, LiveFirstState::Available);
    }

    #[test]
    fn available_stays_available_on_success() {
        let state = LiveFirstState::Available;
        let next = state.transition(&LiveCallOutcome::Success);
        assert_eq!(next, LiveFirstState::Available);
    }

    #[test]
    fn available_to_unavailable_on_connection_failure() {
        let state = LiveFirstState::Available;
        let next = state.transition(&LiveCallOutcome::ConnectionFailure {
            failure_kind: ConnectionFailureKind::Timeout,
        });
        assert_eq!(
            next,
            LiveFirstState::Unavailable {
                reason: ConnectionFailureKind::Timeout,
            }
        );
    }

    #[test]
    fn unavailable_recovers_on_app_error() {
        let state = LiveFirstState::Unavailable {
            reason: ConnectionFailureKind::ConnectionRefused,
        };
        let next = state.transition(&LiveCallOutcome::AppError);
        assert_eq!(next, LiveFirstState::Available);
    }

    #[test]
    fn unavailable_recovers_on_success() {
        let state = LiveFirstState::Unavailable {
            reason: ConnectionFailureKind::ConnectionRefused,
        };
        let next = state.transition(&LiveCallOutcome::Success);
        assert_eq!(next, LiveFirstState::Available);
    }

    // -- should_call_live --

    #[test]
    fn should_call_live_when_untried() {
        assert!(LiveFirstState::Untried.should_call_live());
    }

    #[test]
    fn should_call_live_when_available() {
        assert!(LiveFirstState::Available.should_call_live());
    }

    #[test]
    fn should_not_call_live_when_unavailable() {
        let state = LiveFirstState::Unavailable {
            reason: ConnectionFailureKind::ConnectionRefused,
        };
        assert!(!state.should_call_live());
    }

    // -- Property-based tests --

    fn arb_connection_failure_kind() -> impl Strategy<Value = ConnectionFailureKind> {
        prop_oneof![
            Just(ConnectionFailureKind::ConnectionRefused),
            Just(ConnectionFailureKind::DnsFailure),
            Just(ConnectionFailureKind::AuthError),
            Just(ConnectionFailureKind::Timeout),
        ]
    }

    fn arb_live_call_outcome() -> impl Strategy<Value = LiveCallOutcome> {
        prop_oneof![
            Just(LiveCallOutcome::Success),
            arb_connection_failure_kind().prop_map(|failure_kind| {
                LiveCallOutcome::ConnectionFailure { failure_kind }
            }),
            Just(LiveCallOutcome::AppError),
        ]
    }

    fn arb_live_first_state() -> impl Strategy<Value = LiveFirstState> {
        prop_oneof![
            Just(LiveFirstState::Untried),
            Just(LiveFirstState::Available),
            arb_connection_failure_kind().prop_map(|reason| {
                LiveFirstState::Unavailable { reason }
            }),
        ]
    }

    fn arb_mock_value_space() -> impl Strategy<Value = MockValueSpace> {
        prop_oneof![
            Just(MockValueSpace::LiveFirst),
            Just(MockValueSpace::FixedSet),
            Just(MockValueSpace::Autonomous),
            Just(MockValueSpace::Seeded),
        ]
    }

    proptest! {
        /// Serialization roundtrip for MockValueSpace.
        #[test]
        fn mock_value_space_serde_roundtrip(space in arb_mock_value_space()) {
            let json = serde_json::to_string(&space).expect("serialize");
            let deserialized: MockValueSpace = serde_json::from_str(&json).expect("deserialize");
            prop_assert_eq!(space, deserialized);
        }

        /// Serialization roundtrip for ConnectionFailureKind.
        #[test]
        fn connection_failure_kind_serde_roundtrip(kind in arb_connection_failure_kind()) {
            let json = serde_json::to_string(&kind).expect("serialize");
            let deserialized: ConnectionFailureKind = serde_json::from_str(&json).expect("deserialize");
            prop_assert_eq!(kind, deserialized);
        }

        /// Success outcome always transitions any state to Available.
        #[test]
        fn success_always_transitions_to_available(state in arb_live_first_state()) {
            let next = state.transition(&LiveCallOutcome::Success);
            prop_assert_eq!(next, LiveFirstState::Available);
        }

        /// Connection failure always transitions any state to Unavailable with matching reason.
        #[test]
        fn connection_failure_always_transitions_to_unavailable(
            state in arb_live_first_state(),
            kind in arb_connection_failure_kind(),
        ) {
            let outcome = LiveCallOutcome::ConnectionFailure { failure_kind: kind };
            let next = state.transition(&outcome);
            prop_assert_eq!(next, LiveFirstState::Unavailable { reason: kind });
        }

        /// App error always transitions to Available (proves reachability).
        #[test]
        fn app_error_always_transitions_to_available(state in arb_live_first_state()) {
            let next = state.transition(&LiveCallOutcome::AppError);
            prop_assert_eq!(next, LiveFirstState::Available);
        }

        /// After any single transition, should_call_live is consistent with the resulting state.
        #[test]
        fn should_call_live_consistent_after_transition(
            state in arb_live_first_state(),
            outcome in arb_live_call_outcome(),
        ) {
            let next = state.transition(&outcome);
            match &next {
                LiveFirstState::Untried => prop_assert!(next.should_call_live()),
                LiveFirstState::Available => prop_assert!(next.should_call_live()),
                LiveFirstState::Unavailable { .. } => prop_assert!(!next.should_call_live()),
            }
        }

        /// A known connection failure pattern always classifies as Some(kind).
        #[test]
        fn known_patterns_always_classify(
            prefix in ".{0,20}",
            suffix in ".{0,20}",
        ) {
            // ECONNREFUSED should always be detected regardless of surrounding text.
            let msg = format!("{prefix}ECONNREFUSED{suffix}");
            prop_assert!(classify_connection_failure(&msg).is_some());
        }

        /// Arbitrary strings without any known pattern classify as None.
        #[test]
        fn arbitrary_safe_strings_classify_as_none(msg in "[a-z]{0,50}") {
            // Pure lowercase alpha strings won't contain any of our patterns
            // (patterns have uppercase, digits, or spaces).
            if !CONN_REFUSED_PATTERNS.iter().any(|p| msg.contains(p))
                && !DNS_FAILURE_PATTERNS.iter().any(|p| msg.contains(p))
                && !AUTH_ERROR_PATTERNS.iter().any(|p| msg.contains(p))
                && !TIMEOUT_PATTERNS.iter().any(|p| msg.contains(p))
            {
                prop_assert_eq!(classify_connection_failure(&msg), None);
            }
        }
    }
}
